// src/pages/Upload.js
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Upload.css';

const Upload = () => {
  const navigate = useNavigate();
  
  // User state
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  
  // Upload states
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [courses, setCourses] = useState([]);
  const [loadingCourses, setLoadingCourses] = useState(false);
  const [subjects, setSubjects] = useState([]);
  
  // Complete form data
  const [formData, setFormData] = useState({
    // Basic info
    title: '',
    description: '',
    
    // Academic info
    course: 'B.Tech',
    branch: 'CSE',
    year: '1',
    semester: '1',
    subject: '',
    subject_code: '',
    
    // Material info
    type: 'notes',
    tags: ''
  });

  // Available options
  const courseOptions = ['B.Tech', 'BCA', 'BBA', 'MBA', 'MCA'];
  const branchOptions = ['CSE', 'ECE', 'EEE', 'ME', 'CE', 'IT'];
  const yearOptions = ['1', '2', '3', '4'];
  const semesterOptions = ['1', '2', '3', '4', '5', '6', '7', '8'];
  
  const materialTypes = [
    { value: 'notes', label: '📄 Notes' },
    { value: 'pyq', label: '📝 Previous Year Questions (PYQ)' },
    { value: 'syllabus', label: '📋 Syllabus' },
    { value: 'lab', label: '🔬 Lab Manuals' },
    { value: 'assignment', label: '📝 Assignments' },
    { value: 'presentation', label: '📊 Presentations' },
    { value: 'important', label: '❓ Important Questions' }
  ];

  // Subject database based on course and branch
  const subjectDatabase = {
    'B.Tech': {
      'CSE': {
        '1': {
          '1': ['Mathematics-I', 'Physics', 'Chemistry', 'Programming in C', 'English Communication', 'Engineering Graphics'],
          '2': ['Mathematics-II', 'Digital Electronics', 'Data Structures', 'Discrete Mathematics', 'Environmental Science']
        },
        '2': {
          '3': ['Object Oriented Programming', 'Computer Organization', 'Database Management Systems', 'Theory of Computation', 'Probability & Statistics'],
          '4': ['Operating Systems', 'Computer Networks', 'Design & Analysis of Algorithms', 'Microprocessors', 'Formal Language & Automata']
        },
        '3': {
          '5': ['Software Engineering', 'Compiler Design', 'Computer Graphics', 'Artificial Intelligence', 'Elective-I'],
          '6': ['Machine Learning', 'Cryptography', 'Cloud Computing', 'Data Mining', 'Elective-II']
        },
        '4': {
          '7': ['Big Data Analytics', 'Internet of Things', 'Project Work', 'Elective-III', 'Elective-IV'],
          '8': ['Major Project', 'Seminar', 'Industrial Training']
        }
      },
      'ECE': {
        '1': {
          '1': ['Mathematics-I', 'Physics', 'Chemistry', 'Basic Electrical Engineering', 'Engineering Graphics'],
          '2': ['Mathematics-II', 'Electronic Devices', 'Circuit Theory', 'Signals & Systems', 'Digital Electronics']
        },
        '2': {
          '3': ['Analog Electronics', 'Electromagnetic Theory', 'Control Systems', 'Microprocessors', 'Network Analysis'],
          '4': ['Communication Systems', 'Digital Signal Processing', 'VLSI Design', 'Antenna Theory', 'Embedded Systems']
        }
      }
    },
    'BCA': {
      'Computer Applications': {
        '1': {
          '1': ['Programming Fundamentals', 'Digital Logic', 'Business Communication', 'Mathematics-I', 'Computer Fundamentals'],
          '2': ['Data Structures', 'Database Management', 'Object Oriented Programming', 'Mathematics-II', 'Environmental Studies']
        },
        '2': {
          '3': ['Operating Systems', 'Computer Networks', 'Web Technologies', 'Software Engineering', 'Financial Accounting'],
          '4': ['Java Programming', 'Computer Graphics', 'E-Commerce', 'Management Information Systems', 'Statistics']
        },
        '3': {
          '5': ['Mobile Application Development', 'Cloud Computing', 'Cyber Security', 'Elective-I', 'Project Work-I'],
          '6': ['Artificial Intelligence', 'Big Data Analytics', 'Elective-II', 'Elective-III', 'Major Project']
        }
      }
    },
    'BBA': {
      'General': {
        '1': {
          '1': ['Principles of Management', 'Business Economics', 'Financial Accounting', 'Business Mathematics', 'Business Communication'],
          '2': ['Organizational Behavior', 'Marketing Management', 'Cost Accounting', 'Business Statistics', 'Environmental Studies']
        },
        '2': {
          '3': ['Human Resource Management', 'Production Management', 'Corporate Accounting', 'Business Law', 'Computer Applications'],
          '4': ['Financial Management', 'Research Methodology', 'Taxation', 'Management Accounting', 'Entrepreneurship']
        }
      }
    }
  };

  useEffect(() => {
    // Check authentication
    const savedUser = localStorage.getItem('study_portal_user');
    const savedToken = localStorage.getItem('study_portal_token');
    
    if (savedUser && savedToken) {
      try {
        const userData = JSON.parse(savedUser);
        setUser(userData);
        setIsAuthenticated(true);
        
        // Auto-fill user's academic details
        if (userData.course) setFormData(prev => ({ ...prev, course: userData.course }));
        if (userData.branch) setFormData(prev => ({ ...prev, branch: userData.branch }));
        if (userData.semester) setFormData(prev => ({ ...prev, semester: userData.semester.toString() }));
        
      } catch (error) {
        console.error('Error parsing user:', error);
        navigate('/login');
      }
    } else {
      navigate('/login');
    }
    
    // Load courses from backend
    fetchCoursesFromBackend();
  }, [navigate]);

  // Update subjects when course, branch, year, or semester changes
  useEffect(() => {
    updateSubjects();
    generateSubjectCode();
  }, [formData.course, formData.branch, formData.year, formData.semester]);

  const fetchCoursesFromBackend = async () => {
    try {
      setLoadingCourses(true);
      const response = await fetch('http://localhost:5000/api/courses');
      
      if (response.ok) {
        const data = await response.json();
        setCourses(data.courses || []);
      } else {
        console.warn('Could not fetch courses from backend, using local data');
      }
    } catch (error) {
      console.error('Error fetching courses:', error);
    } finally {
      setLoadingCourses(false);
    }
  };

  const updateSubjects = () => {
    const { course, branch, year, semester } = formData;
    
    let availableSubjects = [];
    
    if (subjectDatabase[course] && subjectDatabase[course][branch]) {
      if (subjectDatabase[course][branch][year] && subjectDatabase[course][branch][year][semester]) {
        availableSubjects = subjectDatabase[course][branch][year][semester];
      }
    }
    
    // Add "Other" option
    if (availableSubjects.length > 0) {
      availableSubjects = [...availableSubjects, 'Other'];
    } else {
      availableSubjects = [
        'Mathematics',
        'Physics', 
        'Chemistry',
        'Computer Science',
        'Electronics',
        'Mechanical',
        'Civil',
        'Electrical',
        'Other'
      ];
    }
    
    setSubjects(availableSubjects);
    
    // Reset subject if not in new list
    if (formData.subject && !availableSubjects.includes(formData.subject)) {
      setFormData(prev => ({ ...prev, subject: '' }));
    }
  };

  const generateSubjectCode = () => {
    const { course, branch, year, semester, subject } = formData;
    
    if (!course || !branch || !year || !semester || !subject) {
      return '';
    }
    
    // Generate code like: BTECH-CSE-1-1-MATH
    const courseCode = course.substring(0, 4).toUpperCase();
    const branchCode = branch.toUpperCase();
    const subjectCode = subject.substring(0, 4).toUpperCase().replace(/\s/g, '');
    
    return `${courseCode}-${branchCode}-${year}${semester}-${subjectCode}`;
  };

  const handleAddSampleCourses = async () => {
    try {
      setLoadingCourses(true);
      const response = await fetch('http://localhost:5000/api/add-courses-public', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
      });
      
      const data = await response.json();
      
      if (response.ok) {
        alert(`✅ ${data.message || 'Courses added successfully!'}`);
        fetchCoursesFromBackend();
      } else {
        alert(`❌ ${data.error || 'Failed to add courses'}`);
      }
    } catch (error) {
      console.error('Error:', error);
      alert('❌ Network error. Check backend connection.');
    } finally {
      setLoadingCourses(false);
    }
  };

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      // Validate file size
      if (selectedFile.size > 10 * 1024 * 1024) {
        alert('❌ File size exceeds 10MB limit');
        e.target.value = '';
        return;
      }
      
      // Validate file type
      const allowedTypes = [
        'application/pdf',
        'application/msword',
        'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'application/vnd.ms-powerpoint',
        'application/vnd.openxmlformats-officedocument.presentationml.presentation',
        'text/plain',
        'image/jpeg',
        'image/png'
      ];
      
      if (!allowedTypes.includes(selectedFile.type)) {
        alert('❌ File type not supported. Please upload PDF, DOC, DOCX, PPT, PPTX, TXT, JPG, or PNG files.');
        e.target.value = '';
        return;
      }
      
      setFile(selectedFile);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const handleUpload = async () => {
    // Validation
    if (!file) {
      alert('❌ Please select a file');
      return;
    }
    
    if (!formData.title.trim()) {
      alert('❌ Please enter title');
      return;
    }
    
    if (!formData.subject) {
      alert('❌ Please select subject');
      return;
    }

    setUploading(true);

    try {
      const token = localStorage.getItem('study_portal_token');
      
      if (!token) {
        throw new Error('Authentication token missing. Please login again.');
      }

      // Prepare FormData for backend
      const data = new FormData();
      
      // Required fields for your backend
      data.append('file', file);
      data.append('title', formData.title);
      data.append('description', formData.description || '');
      data.append('course_id', '1'); // Use first available course ID
      data.append('type', formData.type);
      
      // Additional academic details (will be stored in description or as separate fields)
      const fullDescription = `
${formData.description || ''}

--- Academic Details ---
Course: ${formData.course}
Branch: ${formData.branch}
Year: ${formData.year}
Semester: ${formData.semester}
Subject: ${formData.subject}
Subject Code: ${formData.subject_code || generateSubjectCode()}
Tags: ${formData.tags}
Uploaded by: ${user?.name || 'Unknown'} (${user?.email || 'N/A'})
      `.trim();
      
      data.append('description', fullDescription);

      // Log for debugging
      console.log('Uploading file:', file.name);
      console.log('Form data:', {
        title: formData.title,
        course: formData.course,
        branch: formData.branch,
        year: formData.year,
        semester: formData.semester,
        subject: formData.subject,
        type: formData.type
      });

      // Send to backend
      const response = await fetch('http://localhost:5000/api/upload', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
        },
        body: data,
      });

      console.log('Response status:', response.status);
      
      let result;
      try {
        result = await response.json();
        console.log('Response data:', result);
      } catch (jsonError) {
        console.error('Error parsing JSON:', jsonError);
        throw new Error('Invalid response from server');
      }
      
      if (response.ok) {
        // Success
        alert(`✅ ${result.message || 'File uploaded successfully!'}\n\n📝 Status: ${result.status || 'Pending approval'}\n\n🎓 Details:\n• ${formData.course} - ${formData.branch}\n• Year ${formData.year}, Semester ${formData.semester}\n• Subject: ${formData.subject}\n\n⚠️ Note: File will be visible after admin approval.`);
        
        // Reset form
        resetForm();
        
      } else {
        // Error
        let errorMsg = result.error || 'Server error';
        
        if (response.status === 422) {
          errorMsg = `Validation Error: Please check all fields are filled correctly.\n\nRequired:\n1. Title\n2. Subject\n3. File (PDF/DOC/PPT/IMAGE)\n4. Course ID`;
        }
        
        alert(`❌ Upload failed: ${errorMsg}`);
      }
      
    } catch (error) {
      console.error('Upload error:', error);
      
      if (error.name === 'TypeError' && error.message.includes('fetch')) {
        alert('❌ Network Error: Cannot connect to backend at http://localhost:5000\n\nPlease ensure backend server is running.');
      } else {
        alert(`❌ Upload Error: ${error.message}`);
      }
    } finally {
      setUploading(false);
    }
  };

  const resetForm = () => {
    setFile(null);
    setFormData({
      title: '',
      description: '',
      course: 'B.Tech',
      branch: 'CSE',
      year: '1',
      semester: '1',
      subject: '',
      subject_code: '',
      type: 'notes',
      tags: ''
    });
    document.getElementById('fileInput').value = '';
  };

  const handleLogout = () => {
    localStorage.removeItem('study_portal_token');
    localStorage.removeItem('study_portal_user');
    window.location.href = '/';
  };

  // Show loading while checking authentication
  if (!user && isAuthenticated === false) {
    return (
      <div className="loading-container">
        <div>Loading authentication...</div>
      </div>
    );
  }

  return (
    <div className="upload-container">
      {/* Header */}
      <div className="upload-header-row">
        <header className="upload-header">
          <h1 className="upload-title">Upload Study Materials</h1>
          <p className="upload-subtitle">
            Share your notes, PYQs, and study materials with complete academic details
          </p>
        </header>
        
        <button onClick={handleLogout} className="logout-button">
          Logout
        </button>
      </div>

      {/* User Info */}
      <div className="user-info">
        <div className="user-avatar">
          {user?.name?.charAt(0)?.toUpperCase() || 'U'}
        </div>
        <div className="user-details">
          <p className="user-name">
            Uploading as: <span>{user?.name || 'User'}</span>
          </p>
          <p className="user-meta">
            {user?.branch || 'Branch'} • Semester {user?.semester || 'Semester'} • {user?.email || 'Email'}
          </p>
        </div>
      </div>

      {/* Info Box */}
      <div className="info-box">
        <p><strong>📋 Instructions:</strong> Fill all academic details accurately. This helps students find relevant materials.</p>
      </div>

      {/* File Upload Section */}
      <div className="upload-box">
        <input
          type="file"
          id="fileInput"
          className="file-input"
          onChange={handleFileChange}
          accept=".pdf,.doc,.docx,.ppt,.pptx,.txt,.jpg,.jpeg,.png"
        />
        <label htmlFor="fileInput" className="upload-label">
          📁 Choose File to Upload
        </label>
        
        {file && (
          <div className="file-info">
            <p><strong>Selected:</strong> {file.name}</p>
            <p><strong>Size:</strong> {(file.size / 1024).toFixed(2)} KB</p>
            <p><strong>Type:</strong> {file.type}</p>
          </div>
        )}
        
        <p className="file-types">
          📎 Supported: PDF, DOC, DOCX, PPT, PPTX, TXT, JPG, JPEG, PNG
          <br />
          ⚠️ Maximum file size: 10MB
        </p>
      </div>

      {/* Upload Form */}
      <div className="upload-form">
        <h3 className="form-section-title">📄 Material Details</h3>
        
        {/* Title */}
        <div className="form-group">
          <label className="form-label">
            Title <span className="required">*</span>
            <small>(Descriptive title of your material)</small>
          </label>
          <input
            type="text"
            name="title"
            placeholder="e.g., Complete Data Structures Notes, Operating Systems PYQ 2023"
            value={formData.title}
            onChange={handleInputChange}
            className="form-input"
            required
          />
        </div>

        {/* Description */}
        <div className="form-group">
          <label className="form-label">
            Description <small>(Optional details about the material)</small>
          </label>
          <textarea
            name="description"
            placeholder="Describe what's included in this material, important topics covered, etc."
            value={formData.description}
            onChange={handleInputChange}
            className="form-textarea"
            rows="3"
          />
        </div>

        <h3 className="form-section-title">🎓 Academic Details</h3>
        
        <div className="form-row">
          {/* Course */}
          <div className="form-group half">
            <label className="form-label">Course <span className="required">*</span></label>
            <select
              name="course"
              value={formData.course}
              onChange={handleInputChange}
              className="form-select"
              required
            >
              {courseOptions.map(course => (
                <option key={course} value={course}>{course}</option>
              ))}
            </select>
          </div>

          {/* Branch */}
          <div className="form-group half">
            <label className="form-label">Branch <span className="required">*</span></label>
            <select
              name="branch"
              value={formData.branch}
              onChange={handleInputChange}
              className="form-select"
              required
            >
              {branchOptions.map(branch => (
                <option key={branch} value={branch}>{branch}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="form-row">
          {/* Year */}
          <div className="form-group half">
            <label className="form-label">Year <span className="required">*</span></label>
            <select
              name="year"
              value={formData.year}
              onChange={handleInputChange}
              className="form-select"
              required
            >
              {yearOptions.map(year => (
                <option key={year} value={year}>Year {year}</option>
              ))}
            </select>
          </div>

          {/* Semester */}
          <div className="form-group half">
            <label className="form-label">Semester <span className="required">*</span></label>
            <select
              name="semester"
              value={formData.semester}
              onChange={handleInputChange}
              className="form-select"
              required
            >
              {semesterOptions.map(sem => (
                <option key={sem} value={sem}>Semester {sem}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Subject */}
        <div className="form-group">
          <label className="form-label">Subject <span className="required">*</span></label>
          <select
            name="subject"
            value={formData.subject}
            onChange={handleInputChange}
            className="form-select"
            required
          >
            <option value="">-- Select Subject --</option>
            {subjects.map(subject => (
              <option key={subject} value={subject}>{subject}</option>
            ))}
          </select>
        </div>

        <div className="form-row">
          {/* Subject Code */}
          <div className="form-group half">
            <label className="form-label">
              Subject Code <small>(Auto-generated)</small>
            </label>
            <input
              type="text"
              name="subject_code"
              placeholder="e.g., BTECH-CSE-1-1-MATH"
              value={formData.subject_code || generateSubjectCode()}
              onChange={handleInputChange}
              className="form-input"
              readOnly
              style={{ background: '#f3f4f6' }}
            />
          </div>

          {/* Material Type */}
          <div className="form-group half">
            <label className="form-label">Material Type <span className="required">*</span></label>
            <select
              name="type"
              value={formData.type}
              onChange={handleInputChange}
              className="form-select"
              required
            >
              {materialTypes.map(type => (
                <option key={type.value} value={type.value}>{type.label}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Tags */}
        <div className="form-group">
          <label className="form-label">
            Tags <small>(Comma separated, e.g., important, unit1, theory)</small>
          </label>
          <input
            type="text"
            name="tags"
            placeholder="important, unit1, theory, practical"
            value={formData.tags}
            onChange={handleInputChange}
            className="form-input"
          />
        </div>

        {/* Upload Button */}
        <button
          onClick={handleUpload}
          disabled={uploading || !file || !formData.title || !formData.subject}
          className="upload-btn"
        >
          {uploading ? '⏳ Uploading...' : '📤 Upload Material'}
        </button>

        <div className="admin-note">
          <p className="admin-note-content">
            <span>⚠️</span>
            <span>
              <strong>Note:</strong> All uploads require admin approval. 
              Your file will be visible after review. Please provide accurate details.
            </span>
          </p>
        </div>
      </div>
    </div>
  );
};

export default Upload;
